<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list :IsShowAction="true" :showCheckBox="true" ModuleName="BillingRule" :listType="['List']"
            :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick" SubModuleCode=""
            IdentityColumn="configurationId" :HeaderText="$t('BillingRuleTemplate')" :ListData="BillingRuleData"
            :HeaderData="Headers" :callbackfunction="FetchData" :HeaderButtons="listheaderbuttons"
            :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" :ListDataCallBackFunction="FetchData"
            :LegendArray="[]" :SortExp="sortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')"
            v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata">
            <template v-slot:slotdata="{ data }" :routeInfo="$router">
                <template v-if="data.column.COLUMN_NAME == 'billingTemplateName'">
                    <a :href="OpenRuleTemplateDetail(data.row)"><i aria-hidden="true"></i>{{data.row.billingTemplateName }}
                    </a>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'statusId'">
                    <div>
                        <listing-status :isfor="'BILLING_RULE'" ref="updatestatus"
                            v-bind:dataid="data.row.configurationId" data-controller="BillingRuleTemplate"
                            v-bind:statuslist="StatusListForListing" v-bind:item="data.row.statusId"
                            data-action="UpdateStatus" v-bind:dataselected="data.row.statusId == 1001 ? 'Active' : 'Inactive'"
                            v-bind:callbackfunction="FetchData" v-bind:isselectedvaluestring="true" 
                            :check-privilege="true" v-bind:title="data.row.statusId == 1001 ? 'Active' : 'Inactive'">
                        </listing-status>
                    </div>
                    <div>
                        <span v-bind:class="getStatusClassList(data.row.statusId, 'STATUS_ID')"
                            v-if="data.row.statusId == 'Active'">
                            {{ data.row.statusId }}
                        </span>
                        <span v-bind:class="getStatusClassList(data.row.statusId, 'STATUS_ID')"
                            v-if="data.row.STATUS_ID == 'Inactive'">
                            {{ data.row.statusId }}
                        </span>
                    </div>
                </template>
            </template>
           
        </tg-list>
        <!-- Clone Model  Start-->
        <div name="modal" v-if="isTemplateModel">
             <div class="modal my-popups right fade d-block" :class="{ show: isShownTemplate }">
                <div role="document" class="modal-dialog" style="max-width: 1300px !important;">
                    <div class="modal-content">
                        <div
                            class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">
                                {{ $t('AddBillingRuleFromTemplate') }} 
                            </h5>
                            <button type="button" class="close" @click="CloseRuleTemplateModel">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                            <span class="user-guide">
                                <a class="ancuserguide text-white" data-toggle="collapse" href="javascript:;" role="button" aria-expanded="false" aria-controls="collapseExample">
                                    <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}
                                </a>
                                <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                    <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                        <div class="con"  v-html="getUserGuideTitle()"></div>
                                    </div>
                                </div>
                            </span>
                        </div>

                        <div class="modal-body">
                            <dynamic-form lang="en" ref="validateRuleTemplate" :buttons="buttons" :schema="FormSchema"
                                :mandatorytext="$t('MandatoryString')">
                                 <template v-slot:tgslot-BillingRuleTemplate="{ data }">
                                    <div id="divconversationbox">
                                            <div class="listing">
                                                <div id="accordion" class="w-100">
                                                    <div class="card mb-4">
                                                        <div class="card-header">
                                                            <a class="card-link" data-toggle="collapse" href="#collapseBillingTemplateOne1" style="color: #000 !important;">
                                                                <div class="conversation-date heading-border"><span><b>{{pricingMethod}}</b></span></div>
                                                            </a>
                                                        </div>
                                                        <div id="collapseBillingTemplateOne1" class="collapse show" data-parent="#accordion">
                                                            <div class="card-body">
                                                                <div class="user_type_choice mt-2 coloredicons">
                                                                    <div data-toggle="buttons" class="btn-group btn-group-toggle custom-reports-icons my-2 total_disable_class_bg" v-for="(item, index) in billingTemplateListing" :key="index">
                                                                        <label class="btn btn_cstm lblconfigurationid" :class="{ active: item.configurationId == configId }" :id="'lblconfigurationid_' + item.configurationId"
                                                                            title="Per Ticket Pricing rule">
                                                                        <input type="radio" :id="'ConfigurationId_' + item.configurationId" :value="item.configurationId" class="rdoconfigurationid" v-model="configId">
                                                                        <span class="d-block pb-2">
                                                                            <i aria-hidden="true" class="fa fa-folder-open-o bg-transparent"></i>
                                                                        </span> 
                                                                              {{ item.billingTemplateName }}
                                                                        </label>
                                                                    </div>
                                                                    </div>

                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                    </div>
                                </template>
                            </dynamic-form>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <!-- Clone Model End -->
    </section>
</template>

<script>

import Schema from '../BillingRuleTemplate/RuleTemplateSchema';
import DataService from '../../../services/DataService';
import {
    locateBillingService
} from "../../../services/locateBillingService";
export default {
    //  components: {BillingViewHistory},
    data() {
        return {
            isLoading: false,
            BillingRuleData: [],
            isTemplateModel: false,
            listActions: Schema.listActions,
            listheaderbuttons: Schema.buttons,
            cloneItem: [],
            StatusListForListing: [
                {
                    STATUS: "Active",
                    STATUS_ID: 1001,
                    STATUS_COLOR: "#ffffff",
                    STATUS_BG_COLOR: "#28a745",
                },
                {
                    STATUS: "Inactive",
                    STATUS_ID: 1002,
                    STATUS_COLOR: "#ffffff",
                    STATUS_BG_COLOR: "#d72435",
                },
            ],
            Headers: [
                {
                    "COLUMN_NAME": "billingTemplateName",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('BillingTemplateName'),
                    "DISPLAY_ORDER": 1,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    "COLUMN_NAME": "pricingMethod",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME":  this.$t('PricingMethod'),
                    "DISPLAY_ORDER": 2,
                },
                {
                    "COLUMN_NAME": "statusId",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Status'),
                    "DISPLAY_ORDER": 8,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    "COLUMN_NAME": "createdByName",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('CreatedBy'),
                    "DISPLAY_ORDER": 9,
                }
            ],
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('RuleName'),
                            name: 'RuleName',
                            palceholder: this.$t('RuleName'),
                            value: "",
                            validationRules: {
                                required: true
                            },
                            disabled: false,
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('Client Name'),
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('SearchAndSelectClient'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onSelectionChange
                            },
                            validationRules: {
                                "required": true
                            },
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('IsRuleApllicableToAll'),
                            name: "allutilities",
                            visibility: true,
                            disabled: false,
                            value: "",
                            config: {
                                options: [{ value: "1", name: this.$t('Yes') }, { value: "0", name: this.$t('No') }],
                                onChange: this.onChangeApplicable
                            }
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('UtilityName'),
                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: { selectAll: true,  clear: true },
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": true
                            },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('EffectiveFromDate')+' '+'(M/D/YYYY)',
                            name: "Effectivefrom",
                            value: new Date().toLocaleDateString(),
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                // minDate: new Date(),
                                // onChange: this.setTimerDate,
                                maxDate: false
                            },
                            validationRules: { "required": true },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('EffectiveToDate')+' '+'(M/D/YYYY)',
                            name: "Effectiveto",
                            value: new Date('12/31/2099').toLocaleDateString(),
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                minDate: new Date(),
                                onChange: this.setTimerDate,
                                maxDate: false
                            },
                            validationRules: { "required": true },
                        }
                    ],

                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "SlotField",
                            label: this.$t('BillingRuleTemplate'),
                            name: "BillingRuleTemplate",
                            value: "",
                            visibility: true,
                            placeholder: "",
                            config: {
                                options: [],
                            },
                            validationRules: { "required": false, max: 365 },
                             settings: {
                                isInSlot: true
                            }
                        },
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Save'),
                    onClick: this.SaveBillingRuleTemplate
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.CloseRuleTemplateModel,
                },
            ],
            leftSearchFields: [
                {
                    fieldName: "BillingTemplateName",
                    fieldType: "text",
                    fieldIcon: "fa fa-wpforms",
                    paramName: "RULE_TEMPLATE_NAME",
                    fieldSearchConditionName: ['RULE_TEMPLATE_NAME'],
                    isSearch: false,
                    value: "",
                    listOptions: []
                },
                {
                    fieldName: 'PricingMethod',
                    fieldType: "ddl-radio",
                    fieldIcon: "fa fa-file-text-o",
                    fieldSearchConditionName: ['PRICING_METHOD'],
                    paramName: "PRICING_METHOD",
                    isSearch: false,
                    value: "",
                    listOptions: []
                }
            ],
            searchByRuleTemplate: '',
            searchByPricing: '',
            SortBy: '',
            SortExp: '',
            noRecords: '',
            PageSize: "10",
            PageNumber: "1",
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            searchCondition: '',
            ListingData: [],
            isBillingHistoryPopup:false,
            isBillingType:false,
            setupId:32,
            isShownTemplate:false,
            clientList:[],
            clientname:'',
            configId: null,
            billingTemplateListing:[],
            pricingMethod:''
        }
    },
    created: async function () {
        var vm = this;
        vm.UserType=vm.GetUserInfo.UserType;
        vm.CompanyId = this.GetUserInfo.CompanyId;
        vm.UserId = this.GetUserInfo.ID;
        this.isBillingType = localStorage.getItem('billingType') === 'USIC' ? true : false; 
        await vm.GetBillingChargeTypeList();
        await vm.FetchData();
        await vm.GetCompanylist();
        await vm.GetGroupList();
    },
    methods: {
        GetBillingChargeTypeList: async function () {
            var vm = this;
            await DataService.GetBillingChargeTypeList().then((response) => {
                if (response.data != '' && response.data != null) {                
                    const targetField = vm.leftSearchFields.find(field => field.fieldName === 'PricingMethod');
                    if (targetField) {
                        targetField.listOptions = response.data.map(element => ({ name:  element.CATEGORY_NAME, value: element.CATEGORY_NAME }));
                    }
                } 
            });
        },
        getUserGuideTitle() {
            let text = this.$t('User_Guide_Add_Billing_Rule_From_Template');
            return text
                .replace(/\\n/g, '')
                .replace(/\\t/g, '&nbsp;');
        },
        async getClientNameById(clientId) {
            const client = this.clientList.find(c => c.value === clientId);
            return client ? client.text : '';
        },
        OpenRuleTemplateDetail: function (data) {
            var vm = this;
            if(this.isBillingType){
                return this.$router.resolve({
                        name: 'View',
                        params: { id: data.configurationId,serviceId:data.serviceId,mode :'View' }
                    }).href;
            }
            else{
                return this.$router.resolve({
                        name: 'View',
                        params: {  id: data.CONFIGURATION_ID,serviceId:data.BILLING_SERVICE_ID,mode :'View' }
                    }).href;
            }
        },
        FetchData: async function () {
            var vm = this;
            const url = `search=${vm.searchByRuleTemplate}&pricingMethods=${vm.searchByPricing}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}`
            try {
                const response = await DataService.GetBillingTemplateListing(url);
                if (response.data && response.data.length > 0) {
                    vm.BillingRuleData = response.data;
                    vm.TotalRecords = response.data[0].totaL_RECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                    vm.noRecords = false;

                } else {
                    vm.BillingRuleData = [];
                    vm.TotalRecords = 0;
                    vm.noRecords = true;
                }

            } catch (error) {
                console.error("Error fetching data:", error);
            }
        },
        SaveBillingRuleTemplate: async function () {
            var vm = this;
            const isValid = await vm.$refs.validateRuleTemplate.validateForm.validate();
            if (!isValid) {
                this.isLoading = false;
                return;
            }
            var serviceId = this.isBillingType == true ? vm.cloneItem.serviceId: vm.cloneItem.BILLING_SERVICE_ID;
            var utilityValues = vm.$refs.validateRuleTemplate.getPropertyValue("UtilityName", "value");
            var selectUtility = Array.isArray(utilityValues) ? utilityValues.join(",") : utilityValues;
            var postString = {
                "configurationId": vm.configId,
                "ServiceId": serviceId,
                "RuleName": vm.$refs.validateRuleTemplate.getPropertyValue("RuleName", "value"),
                "ClientId": vm.$refs.validateRuleTemplate.getPropertyValue("ContractName", "value"),
                "IsRuleApllicableToAll": vm.$refs.validateRuleTemplate.getPropertyValue("allutilities", "value"),
                "SelectDivision": selectUtility,
                "CompanyId": 0,
                "CompanyName": "",
                "EffectiveFromDate": vm.$refs.validateRuleTemplate.getPropertyValue("Effectivefrom", "value"),
                "EffectiveToDate": vm.$refs.validateRuleTemplate.getPropertyValue("Effectiveto", "value"),


            };
            await DataService.SaveBillingRuleFromTemplate(postString).then((response) => {
                if (response.data != '') {
                    if (Number(response.data.status) == 0) {
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Rules')]), "Success", true, vm.$t('Alert'));
                        vm.cloneItem = [];
                        vm.CloseRuleTemplateModel();
                    }
                    else if(Number(response.data.status) == 2){
                          vm.ShowAlert(vm.$t("RuleNameAlreadyExists"), "warning", true);
                    }
                    else if(Number(response.data.status) == -11){
                        vm.ShowAlert(vm.$t("RuleNameAlreadyExistsForClient"), "warning", true);
                    }
                    else if(Number(response.data.status) == -22){
                        vm.ShowAlert(vm.$t('RuleNameAlreadyExistsForChildClient', [vm.clientname]), "warning", true, vm.$t("Alert"));
                    }
                    else {
                        vm.ShowAlert(vm.$t('AddedError', [vm.$t('Rules')]), "danger", true, vm.$t('Alert'));
                    }
                }
            })


        },
        onChangeApplicable() {
            var utilityselectval = this.$refs.validateRuleTemplate.getPropertyValue("allutilities", "value");
            switch (utilityselectval) {
                case true:
                    this.$refs.validateRuleTemplate.updateProperty("UtilityName", "visibility", false);
                    this.$refs.validateRuleTemplate.updateProperty("UtilityName", "validationRules.required", false);
                    this.$refs.validateRuleTemplate.updateProperty("UtilityName", "value", "");
                    break;
                default:
                    this.$refs.validateRuleTemplate.updateProperty("UtilityName", "visibility", true);
                    this.$refs.validateRuleTemplate.updateProperty("UtilityName", "validationRules.required", true);
            }

        },
        setTimerDate: function (x, y, z) {
            var vm = this;
            if (y.name == "Effectivefrom") {
                vm.$refs.validateRuleTemplate.updateProperty("Effectivefrom", "config.minDate", x);
                vm.$refs.validateRuleTemplate.UpdateKeyValue();
            }
        },
        GetCompanylist: async function() {
            var vm = this;

            await DataService.GetDdlCompanyList().then((response) => {
                if (response.data != '') {
                    if (response.data.length) {

                        response.data.forEach(element => {
                            var obj = {
                                name: element.Company_Name,
                                value: element.company_id
                            }
                            vm.FormSchema[0].Data[1].config.options.push(obj);
                        })
                    }
                }
            })
        },
        GetGroupList: async function() {
            var vm = this;
            await DataService.GetDdlGroupList().then((response) => {
                if (response.data) {
                    if (response.data.length) {
                        response.data.forEach(element => {
                            var obj = {
                                name: element.CHILD_NAME,
                                value: element.CHILD_USER_ID
                            }
                            vm.FormSchema[0].Data[5].config.options.push(obj);
                        });
                    }
                }
            })
        },

        DeleteData: function () {
            var vm = this;
            var val = "";
            var privilegeParams = `controller=BillingRuleTemplate&action=DeleteRuleTemplate`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val.length > 0) {
                vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("SERVICE")), function () {
                    let url = `ids=${val}&tableName=TALYGEN_BE_CLIENT_CONFIGURATION&primaryKey=CONFIGURATION_ID`;
                    DataService.Delete(url).then(response => {
                        if (response.data == "DeletedSuccess") {
                            vm.ShowAlert(vm.$t('DeletedSuccessfully'), "Success", true, vm.$t('Alert'));
                        } else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('val')]), "failure", true, vm.$t('Alert'));
                        }
                        vm.FetchData();
                    });
                });
            }
            else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"), "failure", true, vm.$t("Alert"));
            }
            }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
        renderActions(row) {
            let rtnActionArray = [];
            this.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                action.isVisible = true;
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                this.searchCondition = value.searchCondition;
                let str = value.searchConditionJson;
                const params = new URLSearchParams(str);
                this.searchByRuleTemplate = params.get('RULE_TEMPLATE_NAME') || '';
                this.searchByPricing = params.get('PRICING_METHOD') || '';
            }
            else {
                this.searchByRuleTemplate = "";
                this.searchByPricing = "";
            }
            this.FetchData();
        },
        actionButtonClick: function (callbackfunction, item, index, event) {
            switch (callbackfunction) {
                case "AddBillingRuleFromTemplate":
                    this.cloneItem = item,
                        this.AddBillingRuleFromTemplate(item);
                    break;
                case "ViewBillingRuleTemplate":
                        this.ViewBillingRuleTemplate(item);
                    break;
                case "EditRuleService":
                    this.EditRuleService(item);
                    break;
            }
        },
        ViewBillingRuleTemplate(data){
            var vm = this;
            if(this.isBillingType){
                vm.$router.push({ name: 'View', params: { id: data.configurationId,serviceId:data.serviceId,mode :'View' } });
            }
            else{
                vm.$router.push({ name: 'View', params: { id: data.CONFIGURATION_ID,serviceId:data.BILLING_SERVICE_ID,mode :'View' } });
            }
        },
        EditRuleService: async function (item) {
            var vm = this;
            if(this.isBillingType){
                vm.$router.push({ name: 'TemplateManageConfiguration', params: { id: item.configurationId, serviceId : item.serviceId,mode :'Edit',ocId: item.configurationId } });
            }
            else{
                vm.$router.push({ name: 'TemplateManageConfiguration', params: { id: item.CONFIGURATION_ID,serviceId:item.BILLING_SERVICE_ID,mode :'Edit',ocId: item.configurationId } });
            }
        },
        AddBillingRuleFromTemplate(item) {
            var vm = this;
            vm.configId = item.configurationId;
            vm.pricingMethod = item.pricingMethod;
            var privilegeParams = `controller=BillingRuleTemplate&action=CloneBillingTemplate`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
                if (response.data) {
                    vm.isTemplateModel = true;
                    vm.GetDDLCompanyContractClients();
                    vm.GetBillingTemplateListGroupByPricingMethod(item.pricingMethod);
                  
                    vm.FormSchema[0].Data[1].value =item.COMPANY_ID;``
                    vm.$nextTick(() => {
                        setTimeout(() => {
                            vm.isShownTemplate = true;
                        }, 50);
                    });
                }
                else {
                    vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                    return false;
                }
            });
        },
        GetBillingTemplateListGroupByPricingMethod(pricingMethod) {
            var vm = this;
            vm.billingTemplateListing=[];
            DataService.GetBillingTemplateListGroupByPricingMethod().then(response => {
                const templateListing = response.data.filter(o => o.pricingMethod === pricingMethod);
                vm.billingTemplateListing = templateListing;
            })
        },
        GetDDLCompanyContractClients: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            await locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                vm.$refs.validateRuleTemplate.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.validateRuleTemplate.UpdateKeyValue();
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = []; 
                vm.$refs.validateRuleTemplate.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.validateRuleTemplate.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        // GetDDLCompanyContractClients: async function () {
