        onSelectionChange: async function(value, x) {
            var vm = this;
            vm.isLoading = true;
            vm.selectedClientId = x;
            vm.clientname = await vm.getClientNameById(x);
            var url = `clientId=${x}&configId=&reqFrom=&clientIds=`;
            await locateBillingService.getUtilityList(url).then(response => {
                vm.isLoading = false;
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                     vm.$refs.validateRuleTemplate.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                     vm.$refs.validateRuleTemplate.UpdateKeyValue();
                }
            }).catch(error => {
                vm.isLoading = false;
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        CloseRuleTemplateModel() {
            var vm = this;
            vm.$nextTick(() => {
            setTimeout(() => {
                vm.isShownTemplate =false;
                }, 50);
            });
            vm.$refs.validateRuleTemplate.updateProperty("RuleName", "value", "");
            vm.$refs.validateRuleTemplate.updateProperty("ContractName", "value", "");
            this.isTemplateModel = false;
            this.cloneItem = [];
            this.FetchData();
        },

        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "AddTemplate":
                    this.AddTemplate();
                    break;
                case "DeleteRecord":
                    this.DeleteData();
                    break;
            }
        },
        sortdata: function (sortBy) {

            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        getStatusClassList: function (status) {

            var returnClass = '';
            switch (status) {
                case 'Active':
                    returnClass = 'px-2 text-center text-white d-block bg-success';
                    break;
                case 'Inactive':
                    returnClass = 'px-2 text-center text-white d-block bg-danger';
                    break;
                default:
                    returnClass = '';
            }
            return returnClass;
        },
        AddTemplate: function () {
            var vm = this;
            vm.$router.push({ name: 'TemplateManageConfiguration', params: { id: 0,serviceId:0,mode :'Add',ocId:0 } });
        },
        UpdataStatus(StatusID, ID, row) {
            var vm = this;
            var privilegeParams = `controller=BillingRuleTemplate&action=UpdateStatus`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
                if (response.data) {
                    var val = "";
                    $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                        if (val.length > 0) {
                            val += ',';
                        }
                        val += $(this).val();
                    });

                    vm.confirmR(vm.$t('AreYouSureToUpdateStatus'), true, false, function (result) {
                        var postJSON = {
                            Id: val || ID,
                            StatusId: StatusID,
                            TableName: "TALYGEN_BE_client_configuration",
                            PrimaryColumn: "configuration_id"
                        };
                        var objectPostString = JSON.stringify(postJSON);
                        locateBillingService.CommonUpdateStatus(objectPostString).then(async response => {
                            if (response.status == 200) {
                                vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
                                vm.FetchData();
                            }
                        });
                    })
                }
                else {
                    vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                    vm.FetchData();
                    return false;
                }
            }, function(rslt){
                row.statusId = (StatusID == 1001)? 1002: 1001;
            });
        },

    }
}
